{"cmd":"cat > content.js <<'EOF'
(() => {
  const CONFIG_KEY = "autoNextEnabled";
  const DEFAULT_ENABLED = true;

  let isEnabled = DEFAULT_ENABLED;
  const processedVideos = new WeakSet();

  function isYouTubeShorts() {
    return location.hostname.includes("youtube.com") && location.pathname.startsWith("/shorts/");
  }

  function isFacebookReels() {
    const host = location.hostname;
    return host.includes("facebook.com") &&
      (location.pathname.startsWith("/reel/") ||
        location.pathname.startsWith("/reels/") ||
        location.pathname.startsWith("/watch/"));
  }

  function clickFirstVisible(selectors) {
    for (const selector of selectors) {
      const nodes = document.querySelectorAll(selector);
      for (const node of nodes) {
        const el = node;
        const style = window.getComputedStyle(el);
        if (style.display !== "none" && style.visibility !== "hidden" && !el.disabled) {
          el.click();
          return true;
        }
      }
    }

    return false;
  }

  function dispatchNavKey(key) {
    const keyboardEventInit = {
      key,
      code: key,
      bubbles: true,
      cancelable: true
    };

    document.dispatchEvent(new KeyboardEvent("keydown", keyboardEventInit));
    document.dispatchEvent(new KeyboardEvent("keyup", keyboardEventInit));
  }

  function goNextYouTube() {
    const clicked = clickFirstVisible([
      "#navigation-button-down button",
      "ytd-reel-player-overlay-renderer #navigation-button-down button",
      "button[aria-label*='Next']",
      "button[aria-label*='Tiếp theo']"
    ]);

    if (!clicked) {
      dispatchNavKey("ArrowDown");
    }
  }

  function goNextFacebook() {
    const clicked = clickFirstVisible([
      "div[aria-label='Next video']",
      "div[aria-label='Video tiếp theo']",
      "[aria-label='Next reel']",
      "[aria-label='Reel tiếp theo']",
      "[aria-label*='Next']",
      "[aria-label*='tiếp theo']"
    ]);

    if (!clicked) {
      dispatchNavKey("PageDown");
      setTimeout(() => dispatchNavKey("ArrowDown"), 100);
    }
  }

  function goNext() {
    if (!isEnabled) {
      return;
    }

    if (isYouTubeShorts()) {
      goNextYouTube();
      return;
    }

    if (isFacebookReels()) {
      goNextFacebook();
    }
  }

  function attachVideoEndedHandler(video) {
    if (processedVideos.has(video)) {
      return;
    }

    processedVideos.add(video);

    video.addEventListener("ended", () => {
      if (!isEnabled) {
        return;
      }

      setTimeout(goNext, 300);
    });
  }

  function scanVideos() {
    const videos = document.querySelectorAll("video");
    videos.forEach((video) => attachVideoEndedHandler(video));
  }

  function setupObserver() {
    const observer = new MutationObserver(() => {
      scanVideos();
    });

    observer.observe(document.documentElement, {
      childList: true,
      subtree: true
    });
  }

  function updateEnabledFromStorage() {
    chrome.storage.sync.get([CONFIG_KEY], (result) => {
      if (chrome.runtime.lastError) {
        return;
      }

      if (typeof result[CONFIG_KEY] === "boolean") {
        isEnabled = result[CONFIG_KEY];
      } else {
        isEnabled = DEFAULT_ENABLED;
      }
    });
  }

  chrome.storage.onChanged.addListener((changes, area) => {
    if (area !== "sync" || !changes[CONFIG_KEY]) {
      return;
    }

    isEnabled = Boolean(changes[CONFIG_KEY].newValue);
  });

  updateEnabledFromStorage();
  scanVideos();
  setupObserver();
  setInterval(scanVideos, 2000);
})();
EOF"}

