{"cmd":"cat > popup.js <<'EOF'
const CONFIG_KEY = "autoNextEnabled";
const toggleEl = document.getElementById("toggle");
const statusEl = document.getElementById("status");

function renderStatus(enabled) {
  statusEl.textContent = enabled ? "Status: ON" : "Status: OFF";
}

chrome.storage.sync.get([CONFIG_KEY], (result) => {
  const enabled = typeof result[CONFIG_KEY] === "boolean" ? result[CONFIG_KEY] : true;
  toggleEl.checked = enabled;
  renderStatus(enabled);
});

toggleEl.addEventListener("change", () => {
  const enabled = toggleEl.checked;

  chrome.storage.sync.set({ [CONFIG_KEY]: enabled }, () => {
    renderStatus(enabled);
  });
});
EOF"}

