{"cmd":"cat > content.js <<'EOF'
const DEFAULT_SETTINGS = {
  enabled: true,
  youtube: true,
  facebook: true,
  delayMs: 700,
};

const FACEBOOK_END_THRESHOLD_SEC = 0.35;
const NEXT_COOLDOWN_MS = 1200;

let settings = { ...DEFAULT_SETTINGS };
let currentVideo = null;
let nextInProgress = false;
let facebookNearEndTriggered = false;
let lastVideoSignature = "";

const wait = (ms) => new Promise((resolve) => setTimeout(resolve, ms));

function isYouTubeShorts() {
  const host = window.location.hostname;
  const path = window.location.pathname;
  return /(^|\.)youtube\.com$/.test(host) && path.startsWith("/shorts/");
}

function isFacebookReels() {
  const host = window.location.hostname;
  const path = window.location.pathname;
  return /(^|\.)facebook\.com$/.test(host) && (path.includes("/reel/") || path.includes("/reels/") || path.includes("/watch/"));
}

function canRunOnCurrentPage() {
  if (!settings.enabled) return false;
  if (isYouTubeShorts()) return settings.youtube;
  if (isFacebookReels()) return settings.facebook;
  return false;
}

function dispatchKey(key) {
  const target = document.activeElement || document.body;
  const keydown = new KeyboardEvent("keydown", { key, bubbles: true, cancelable: true });
  const keyup = new KeyboardEvent("keyup", { key, bubbles: true, cancelable: true });
  target.dispatchEvent(keydown);
  target.dispatchEvent(keyup);
}

function isElementClickable(el) {
  if (!(el instanceof HTMLElement)) return false;

  const style = window.getComputedStyle(el);
  if (style.display === "none" || style.visibility === "hidden" || style.pointerEvents === "none") {
    return false;
  }

  const rect = el.getBoundingClientRect();
  return rect.width > 0 && rect.height > 0;
}

function clickFirstVisible(selectors) {
  for (const selector of selectors) {
    const nodes = document.querySelectorAll(selector);
    for (const node of nodes) {
      if (!isElementClickable(node)) continue;
      node.click();
      return true;
    }
  }

  return false;
}

function clickButtonByLabelRegex(regex) {
  const buttons = Array.from(document.querySelectorAll("button,[role='button']"));
  const match = buttons.find((el) => {
    if (!isElementClickable(el)) return false;

    const label = [
      el.getAttribute("aria-label") || "",
      el.getAttribute("title") || "",
      el.textContent || "",
    ]
      .join(" ")
      .trim();

    return regex.test(label);
  });

  if (!match) return false;
  match.click();
  return true;
}

async function goToNextShort() {
  if (isYouTubeShorts()) {
    const bySelector = clickFirstVisible([
      "#navigation-button-down button",
      "ytd-shorts ytd-button-renderer#button button",
      "button[aria-label*='Next']",
      "button[title*='Next']",
    ]);

    if (!bySelector) {
      const byLabel = clickButtonByLabelRegex(/next|tiep|tiếp|sau/i);
      if (!byLabel) {
        dispatchKey("ArrowDown");
        dispatchKey("PageDown");
      }
    }
    return;
  }

  if (isFacebookReels()) {
    const bySelector = clickFirstVisible([
      "[aria-label='Next video']",
      "[aria-label='Video tiếp theo']",
      "[aria-label='Next reel']",
      "[aria-label='Reel tiếp theo']",
      "div[aria-label*='Next']",
      "button[aria-label*='Next']",
      "[aria-label*='tiếp theo']",
      "[data-testid='next_button']",
    ]);

    if (!bySelector) {
      const byLabel = clickButtonByLabelRegex(/next|tiep|tiếp|sau/i);
      if (!byLabel) {
        dispatchKey("ArrowDown");
        dispatchKey("PageDown");
        window.scrollBy({ top: window.innerHeight * 0.9, behavior: "smooth" });
      }
    }
  }
}

function getVideoSignature(video) {
  const src = video.currentSrc || video.src || "";
  const duration = Number.isFinite(video.duration) ? video.duration.toFixed(2) : "na";
  return `${src}|${duration}`;
}

async function triggerNextOnce() {
  if (!canRunOnCurrentPage()) return;
  if (nextInProgress) return;

  nextInProgress = true;

  try {
    await wait(settings.delayMs);
    await goToNextShort();
  } finally {
    setTimeout(() => {
      nextInProgress = false;
    }, NEXT_COOLDOWN_MS);
  }
}

function handleVideoEnded() {
  triggerNextOnce();
}

function handleVideoProgress() {
  if (!currentVideo) return;
  if (!isFacebookReels()) return;
  if (!canRunOnCurrentPage()) return;

  const signature = getVideoSignature(currentVideo);
  if (signature !== lastVideoSignature) {
    lastVideoSignature = signature;
    facebookNearEndTriggered = false;
  }

  if (currentVideo.currentTime < 1) {
    facebookNearEndTriggered = false;
    return;
  }

  const duration = currentVideo.duration;
  if (!Number.isFinite(duration) || duration <= 0) return;

  const remaining = duration - currentVideo.currentTime;
  if (remaining <= FACEBOOK_END_THRESHOLD_SEC && !facebookNearEndTriggered) {
    facebookNearEndTriggered = true;
    triggerNextOnce();
  }
}

function bindVideo(video) {
  if (!(video instanceof HTMLVideoElement)) return;
  if (video === currentVideo) return;

  if (currentVideo) {
    currentVideo.removeEventListener("ended", handleVideoEnded);
    currentVideo.removeEventListener("timeupdate", handleVideoProgress);
  }

  currentVideo = video;
  lastVideoSignature = getVideoSignature(video);
  facebookNearEndTriggered = false;

  currentVideo.addEventListener("ended", handleVideoEnded);
  currentVideo.addEventListener("timeupdate", handleVideoProgress);
}

function scanAndBindVideo() {
  if (!canRunOnCurrentPage()) return;

  const videos = Array.from(document.querySelectorAll("video"));
  if (videos.length === 0) return;

  const active = videos.find((v) => !v.paused && v.readyState > 1) || videos[0];
  bindVideo(active);
}

async function loadSettings() {
  const stored = await chrome.storage.sync.get(Object.keys(DEFAULT_SETTINGS));
  settings = { ...DEFAULT_SETTINGS, ...stored };
}

function watchStorage() {
  chrome.storage.onChanged.addListener((changes, area) => {
    if (area !== "sync") return;

    for (const key of Object.keys(DEFAULT_SETTINGS)) {
      if (changes[key]) {
        settings[key] = changes[key].newValue;
      }
    }
  });
}

function initObservers() {
  const observer = new MutationObserver(() => {
    scanAndBindVideo();
  });

  observer.observe(document.documentElement, {
    childList: true,
    subtree: true,
  });

  window.addEventListener("popstate", scanAndBindVideo);
  document.addEventListener("visibilitychange", () => {
    if (!document.hidden) scanAndBindVideo();
  });

  setInterval(scanAndBindVideo, 1200);
}

(async function init() {
  await loadSettings();
  watchStorage();
  scanAndBindVideo();
  initObservers();
})();
EOF"}

